var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"흐음......","JPN":"ふむ……","ENG":"Hmm...","TWN":"嗯……"},"stage":{"bg":"COUNTERSIDE_WITCH","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"붉은 연금석 열두 개, 침식된 호박 결정 일흔 한 개, 이터니움 원석에서 자란 린넨 서른 줄기......","JPN":"赤い錬金石12個、侵食された琥珀の結晶71個、\\nエタニウム原石で育ったリネン素材30個……","ENG":"A dozen red alchemy stones, 71 corrupted pumpkin crystals, 30 strands of linen grown from Eternium ore...","TWN":"紅色煉金石十二個，被侵蝕的琥珀結晶七十一個，長在能晶原石的亞麻三十條……"},"stage":{"bg":"COUNTERSIDE_WITCH","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"이 정도면 충분하겠네. 다들 수고했어.","JPN":"このくらいあれば十分ね。みんなお疲れ様。","ENG":"This should be enough. Good work, everyone.","TWN":"這些應該足夠了，妳們辛苦了。"},"stage":{"bg":"COUNTERSIDE_WITCH","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"YOONA_STREGA_NULL_NULL","text":{"KOREA":"하아, 하아...... 정말 죽는 줄 알았어......","JPN":"はぁ、はぁ……本当に死ぬかと思った……","ENG":"*Huff, huff* I really thought I was going to die...","TWN":"哈，哈啊……我快要死了……"},"stage":{"bg":"COUNTERSIDE_WITCH","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"INGRID_STREGA_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L8_1","type":"dialog","speaker":"INGRID_STREGA_NULL_NULL","text":{"KOREA":"후후...... 이 몸에게 피로라는 것을 느끼게 하다니, 침식체 녀석들도 제법인데.","JPN":"ふふ……私に疲れを感じさせるなんて、侵食体のやつらも大したものね。","ENG":"Hah hah... Those C.O.s weren't half bad... they actually got me a little worn out.","TWN":"呼呼……沒想到能讓我感受到疲勞，這些侵蝕體也是了不起啊。"},"stage":{"bg":"COUNTERSIDE_WITCH","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"INGRID_STREGA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"YOONA_STREGA_NULL_NULL","text":{"KOREA":"그런데 정말 이런 괴상한 재료들로 할로윈 코스튬을 만들 수 있는 거예요?","JPN":"ところで、本当にこんな奇妙な材料でハロウィンコスチュームを作れるんですか？","ENG":"But can we seriously make Halloween costumes from such weird materials?","TWN":"可是用這些奇怪的材料真的能製作萬聖節服裝嗎？"},"stage":{"bg":"COUNTERSIDE_WITCH","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"INGRID_STREGA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"YOONA_STREGA_NULL_NULL","text":{"KOREA":"코스튬이 아니라 누더기도 못 만들 것 같은데......","JPN":"コスチュームどころか、ぼろ着すら作れなさそうですが……","ENG":"You could hardly sew a rag together with this... let alone a fancy costume...","TWN":"別說是服裝了，感覺連個破抹布都做不了啊……"},"stage":{"bg":"COUNTERSIDE_WITCH","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"INGRID_STREGA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"후훗. 우리 유나가 호기심이 많구나.","JPN":"ふふっ。ユナは好奇心旺盛なのね。","ENG":"Well, aren't you a curious little thing.","TWN":"哼哼，我們尤娜好像很好奇呢。"},"stage":{"bg":"COUNTERSIDE_WITCH","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"겉보기엔 볼품없지만, 이 재료들에는 입은 사람의 매력을 북돋아 주는 신비한 힘이 깃들어 있어.","JPN":"見た目はよくないけど、この材料には服を着た人の魅力を引き立ててくれる不思議な力があるの。","ENG":"Although they may not look like much, they bear a mysterious power that enhances the wearer's attractiveness.","TWN":"雖然看起來不怎樣，但這些材料裡有一種神秘的力量，可以提升人的魅力。"},"stage":{"bg":"COUNTERSIDE_WITCH","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"이걸로 옷을 만들기 시작한 뒤로 할로윈 코스튬 경연 대회에서 1등을 놓친 적이 없단다.","JPN":"これで服を作り始めて以来、ハロウィンコスチュームコンテストで1位を逃したことがないわ。","ENG":"Ever since we began fashioning costumes from these, our products always placed first in the Halloween costume competitions.","TWN":"用這些製成衣服之後，每年萬聖節扮裝大會的第一名就是我們的囊中之物了。"},"stage":{"bg":"COUNTERSIDE_WITCH","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"정확히는 내가 만든 코스튬이 말이야.","JPN":"正確には妾が作ったコスチュームだがな。","ENG":"Well, the costumes that I made, to be precise.","TWN":"準確地來說，是穿了我做的服裝。"},"stage":{"bg":"COUNTERSIDE_WITCH","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_PRIDE"}}}},{"id":"L18_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"그래? 작년의 참패는 벌써 잊었나 봐?","JPN":"そう？　去年の惨敗をもう忘れたの？","ENG":"Is that right? Have you forgotten about your embarrassing loss last year already?","TWN":"是嗎？看來妳已經忘了去年的敗績？"},"stage":{"bg":"COUNTERSIDE_WITCH","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_PRIDE"}}}},{"id":"L19_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"이제 네 클래식한 디자인은 한 물 갔다는 걸 인정해야 할 때 아닐까?","JPN":"あなたのクラシックなデザインはもはや時代遅れだってことを認めるべきじゃない？","ENG":"Don't you think it's time to admit your classic designs are really out of fashion now?","TWN":"妳現在也該承認妳的經典設計已經過時了吧？"},"stage":{"bg":"COUNTERSIDE_WITCH","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_PRIDE"}}}},{"id":"L20_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"훌륭한 마녀라면 트렌드를 읽을 줄 알아야지.","JPN":"立派な魔女ならトレンドを読まなきゃ。","ENG":"A good witch ought to know how to keep up with the trends.","TWN":"優秀的魔女必須時刻跟隨潮流。"},"stage":{"bg":"COUNTERSIDE_WITCH","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_PRIDE"}}}},{"id":"L21_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"어디서 근본도 없는 잡탕 디자인을 가져와 놓고는 마녀의 옷이라고 우기는 거야?","JPN":"どこの馬の骨かもわからないごちゃ混ぜのデザインが魔女の服だと言い張る気か？","ENG":"You think your hodgepodge random mess is proper witch attire?","TWN":"這種設計妳也拿得出手，還敢說是魔女的衣服？"},"stage":{"bg":"COUNTERSIDE_WITCH","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_HATE"}}}},{"id":"L22_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"지조도 없는 속물 같으니. 빗자루 타다 확 떨어져 버리라지.","JPN":"節操もくそもない俗物め。ホウキの上から落っこちてしまえ。","ENG":"You crude, sorry excuse of a witch. I hope you fall off your broom.","TWN":"真是庸俗，小心坐掃把飛行的時候掉下來。"},"stage":{"bg":"COUNTERSIDE_WITCH","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"YOONA_STREGA_NULL_NULL","text":{"KOREA":"저기, 그런 이상한 힘으로 우승하면 반칙 아니에요?","JPN":"あの、そんな不思議な力で優勝したら反則なんじゃ？","ENG":"Um... Isn't it cheating if you win using a secret power like that?","TWN":"可是，用那種奇怪的力量獲勝，難道不是犯規嗎？"},"stage":{"bg":"COUNTERSIDE_WITCH","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"누구에게나 남들보다 돋보이고 싶은 욕망이 있어.","JPN":"誰にだって人より目立ちたい願望があるものよ。","ENG":"Everyone wants to stand out from a crowd sometimes.","TWN":"誰都有想獨領風騷的慾望。"},"stage":{"bg":"COUNTERSIDE_WITCH","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"할로윈은 그걸 해소하기 좋은 기회지. 특별한 분장으로 평소와 다른 내가 될 수 있으니까.","JPN":"ハロウィンはそんな願望を叶えるいい機会なの。特別なコスチュームで普段とは違う自分になれるから。","ENG":"Halloween is the best opportunity to satisfy that craving. You get to become someone else behind that costume.","TWN":"而萬聖節正是滿足慾望的好機會。因為可以通過特殊的裝扮來展現與眾不同的自己。"},"stage":{"bg":"COUNTERSIDE_WITCH","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"누군가에게 꿈결 같은 하루를 선사하는 것. 그거야말로 우리 같은 착한 마녀가 할 일 아닐까?","JPN":"誰かに夢のような一日を贈ること。それこそが私たちのような優しい魔女の仕事じゃないかしら。","ENG":"Our costumes help folks fulfill their dreams for one day. Isn't that what any good witch should do?","TWN":"為他們呈上夢幻般的一天，那不就是我們這種善良的魔女應該做的事情嗎？"},"stage":{"bg":"COUNTERSIDE_WITCH","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"입에 발린 말은 됐고.","JPN":"綺麗事を言ってるんじゃない。","ENG":"Don't sugarcoat it.","TWN":"別說得那麼冠冕堂皇。"},"stage":{"bg":"COUNTERSIDE_WITCH","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"애초에 경연 대회에서 특이한 재료를 쓰지 말라는 규정은 없어.","JPN":"そもそもコンテストに特別な材料を使ってはいけないという規定はない。","ENG":"There are no competition rules banning the use of unusual materials.","TWN":"本來大賽就沒有不能用特殊材料的規定。"},"stage":{"bg":"COUNTERSIDE_WITCH","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"그러니까 잔소리 그만하고 재료들이나 주워 담아. 올해는 주문이 많이 몰려서 바쁘니까.","JPN":"だからつべこべ言わないで、材料を運べ。今年は注文が多くて忙しいからな。","ENG":"So stop getting so preachy and finish collecting the materials. We're really busy this year with all the orders.","TWN":"別囉嗦了，趕緊裝材料吧。今年訂單多。會很忙。"},"stage":{"bg":"COUNTERSIDE_WITCH","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"YOONA_STREGA_NULL_NULL","text":{"KOREA":"우으...... 할머니가 일구던 텃밭에 다시 끌려 온 것 같아......","JPN":"うう……お婆ちゃんが耕してた畑に連れ出された気分……","ENG":"Ow... I feel like I'm on one of those gardening trips to grandma's farm...","TWN":"額……感覺好像回到了奶奶的田裡……"},"stage":{"bg":"COUNTERSIDE_WITCH","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}}]`);export{e as default};